import { sql, relations } from "drizzle-orm";
import { 
  pgTable, 
  text, 
  varchar, 
  timestamp, 
  integer, 
  decimal, 
  boolean,
  date,
  pgEnum
} from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// Enums
export const activityEnum = pgEnum('activity', [
  'karate',
  'kickboxing', 
  'football',
  'swimming',
  'zumba',
  'aerobics',
  'crossfit',
  'gymnastics',
  'quran_memorization',
  'kindergarten'
]);

export const paymentMethodEnum = pgEnum('payment_method', [
  'cash',
  'visa',
  'bank_transfer'
]);

export const paymentStatusEnum = pgEnum('payment_status', [
  'pending',
  'completed',
  'overdue',
  'cancelled'
]);

export const subscriptionStatusEnum = pgEnum('subscription_status', [
  'active',
  'paused',
  'expired',
  'renewal_due',
  'cancelled'
]);

export const sessionStatusEnum = pgEnum('session_status', [
  'scheduled',
  'attended',
  'missed',
  'cancelled'
]);

export const attendanceStatusEnum = pgEnum('attendance_status', [
  'present',
  'absent',
  'late',
  'excused'
]);

// Players table
export const players = pgTable("players", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  fullName: text("full_name").notNull(),
  dateOfBirth: date("date_of_birth").notNull(),
  phoneNumber: text("phone_number"),
  email: text("email"),
  activity: activityEnum("activity").notNull(),
  subscriptionDate: timestamp("subscription_date").notNull().defaultNow(),
  subscriptionEndDate: timestamp("subscription_end_date"),
  renewalDate: timestamp("renewal_date").notNull(),
  subscriptionStatus: subscriptionStatusEnum("subscription_status").notNull().default('active'),
  pausedDate: timestamp("paused_date"),
  pauseReason: text("pause_reason"),
  totalSessionsAllowed: integer("total_sessions_allowed").notNull().default(8),
  sessionsAttended: integer("sessions_attended").notNull().default(0),
  // Flexible subscription pricing
  monthlySubscriptionFee: decimal("monthly_subscription_fee", { precision: 10, scale: 2 }).notNull().default('100'),
  discountPercentage: decimal("discount_percentage", { precision: 5, scale: 2 }).default('0'),
  specialNotes: text("special_notes"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
  updatedAt: timestamp("updated_at").notNull().defaultNow(),
});

// Player documents table
export const playerDocuments = pgTable("player_documents", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  playerId: varchar("player_id").notNull().references(() => players.id, { onDelete: 'cascade' }),
  documentType: text("document_type").notNull(), // 'id', 'medical_form', etc.
  fileName: text("file_name").notNull(),
  filePath: text("file_path").notNull(),
  fileSize: integer("file_size").notNull(),
  mimeType: text("mime_type").notNull(),
  uploadedAt: timestamp("uploaded_at").notNull().defaultNow(),
});

// Payments table
export const payments = pgTable("payments", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  playerId: varchar("player_id").notNull().references(() => players.id, { onDelete: 'cascade' }),
  subscriptionFee: decimal("subscription_fee", { precision: 10, scale: 2 }).notNull(),
  amountPaid: decimal("amount_paid", { precision: 10, scale: 2 }).notNull(),
  remainingBalance: decimal("remaining_balance", { precision: 10, scale: 2 }).notNull().default('0'),
  paymentMethod: paymentMethodEnum("payment_method").notNull(),
  paymentStatus: paymentStatusEnum("payment_status").notNull().default('completed'),
  paymentDate: timestamp("payment_date").notNull().defaultNow(),
  description: text("description"),
  receiptNumber: text("receipt_number").notNull(),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Payment History/Archive table for old payment records
export const paymentHistory = pgTable("payment_history", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  playerId: varchar("player_id").notNull().references(() => players.id, { onDelete: 'cascade' }),
  subscriptionFee: decimal("subscription_fee", { precision: 10, scale: 2 }).notNull(),
  amountPaid: decimal("amount_paid", { precision: 10, scale: 2 }).notNull(),
  remainingBalance: decimal("remaining_balance", { precision: 10, scale: 2 }).notNull().default('0'),
  paymentMethod: paymentMethodEnum("payment_method").notNull(),
  paymentStatus: paymentStatusEnum("payment_status").notNull().default('completed'),
  paymentDate: timestamp("payment_date").notNull().defaultNow(),
  description: text("description"),
  receiptNumber: text("receipt_number").notNull(),
  subscriptionPeriodStart: timestamp("subscription_period_start").notNull(),
  subscriptionPeriodEnd: timestamp("subscription_period_end").notNull(),
  archivedAt: timestamp("archived_at").notNull().defaultNow(),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Sessions table
export const sessions = pgTable("sessions", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  playerId: varchar("player_id").notNull().references(() => players.id, { onDelete: 'cascade' }),
  sessionDate: timestamp("session_date").notNull(),
  scheduledStartTime: timestamp("scheduled_start_time").notNull(),
  scheduledEndTime: timestamp("scheduled_end_time").notNull(),
  actualStartTime: timestamp("actual_start_time"),
  actualEndTime: timestamp("actual_end_time"),
  attendanceStatus: attendanceStatusEnum("attendance_status").notNull().default('present'),
  sessionStatus: sessionStatusEnum("session_status").notNull().default('scheduled'),
  instructorName: text("instructor_name"),
  notes: text("notes"),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

// Relations
export const playersRelations = relations(players, ({ many }) => ({
  documents: many(playerDocuments),
  payments: many(payments),
  paymentHistory: many(paymentHistory),
  sessions: many(sessions),
}));

export const playerDocumentsRelations = relations(playerDocuments, ({ one }) => ({
  player: one(players, {
    fields: [playerDocuments.playerId],
    references: [players.id],
  }),
}));

export const paymentsRelations = relations(payments, ({ one }) => ({
  player: one(players, {
    fields: [payments.playerId],
    references: [players.id],
  }),
}));

export const paymentHistoryRelations = relations(paymentHistory, ({ one }) => ({
  player: one(players, {
    fields: [paymentHistory.playerId],
    references: [players.id],
  }),
}));

export const sessionsRelations = relations(sessions, ({ one }) => ({
  player: one(players, {
    fields: [sessions.playerId],
    references: [players.id],
  }),
}));

// Insert schemas
export const insertPlayerSchema = createInsertSchema(players).omit({
  id: true,
  createdAt: true,
  updatedAt: true,
  sessionsAttended: true,
  subscriptionStatus: true,
});

export const insertPlayerDocumentSchema = createInsertSchema(playerDocuments).omit({
  id: true,
  uploadedAt: true,
});

export const insertPaymentSchema = createInsertSchema(payments).omit({
  id: true,
  createdAt: true,
  receiptNumber: true,
});

export const insertSessionSchema = createInsertSchema(sessions).omit({
  id: true,
  createdAt: true,
});

export const insertPaymentHistorySchema = createInsertSchema(paymentHistory).omit({
  id: true,
  createdAt: true,
  archivedAt: true,
});

// Types
export type Player = typeof players.$inferSelect;
export type InsertPlayer = z.infer<typeof insertPlayerSchema>;

export type PlayerDocument = typeof playerDocuments.$inferSelect;
export type InsertPlayerDocument = z.infer<typeof insertPlayerDocumentSchema>;

export type Payment = typeof payments.$inferSelect;
export type InsertPayment = z.infer<typeof insertPaymentSchema>;

export type PaymentHistory = typeof paymentHistory.$inferSelect;
export type InsertPaymentHistory = z.infer<typeof insertPaymentHistorySchema>;

export type Session = typeof sessions.$inferSelect;
export type InsertSession = z.infer<typeof insertSessionSchema>;

// Activity display mapping
export const ACTIVITY_DISPLAY = {
