export function generateReceipt(player: Player, payment: Payment) {
  const pdf = new jsPDF();

  // Header with E1 branding
  pdf.setFontSize(20);
  pdf.setTextColor(30, 64, 175); // Academy blue
  pdf.text('E1 Sport', 105, 30, { align: 'center' });

  pdf.setFontSize(14);
  pdf.setTextColor(220, 38, 38); // Academy red
  pdf.text('Champions Academy', 105, 40, { align: 'center' });

  pdf.setFontSize(12);
  pdf.setTextColor(0, 0, 0);
  pdf.text('Payment Receipt', 105, 55, { align: 'center' });

  // Receipt details
  const startY = 80;

  pdf.text(`Receipt #: ${payment.receiptNumber}`, 20, startY);
  pdf.text(`Player: ${player.fullName}`, 20, startY + 10);

  const activity = ACTIVITIES[player.activity as keyof typeof ACTIVITIES];
  pdf.text(`Activity: ${activity?.emoji} ${activity?.label}`, 20, startY + 20);

  pdf.text(`Date: ${new Date(payment.paymentDate).toLocaleDateString()}`, 20, startY + 30);

  const paymentMethod = PAYMENT_METHODS[payment.paymentMethod as keyof typeof PAYMENT_METHODS];
  pdf.text(`Payment Method: ${paymentMethod?.label}`, 20, startY + 40);

  // Payment breakdown
  pdf.line(20, startY + 55, 190, startY + 55);

  pdf.text(`Subscription Fee: $${payment.subscriptionFee}`, 20, startY + 70);
  pdf.text(`Amount Paid: $${payment.amountPaid}`, 20, startY + 80);
  pdf.text(`Balance Remaining: $${payment.remainingBalance}`, 20, startY + 90);

  pdf.line(20, startY + 105, 190, startY + 105);

  // Footer
  pdf.setFontSize(10);
  pdf.setTextColor(100, 100, 100);
  pdf.text('Thank you for choosing E1 Sport Champions Academy', 105, startY + 120, { align: 'center' });

  return pdf;
}

export function generatePlayerProfile(player: Player, payments: Payment[], sessions: any[]) {
  const pdf = new jsPDF();

  // Header
  pdf.setFontSize(20);
  pdf.setTextColor(30, 64, 175);
  pdf.text('E1 Sport Champions Academy', 105, 30, { align: 'center' });

  pdf.setFontSize(16);
  pdf.setTextColor(0, 0, 0);
  pdf.text('Player Profile', 105, 45, { align: 'center' });

  // Player details
  const startY = 70;

  pdf.setFontSize(14);
  pdf.text(`Name: ${player.fullName}`, 20, startY);
  pdf.text(`Player ID: ${player.id}`, 20, startY + 15);
  pdf.text(`Date of Birth: ${new Date(player.dateOfBirth).toLocaleDateString()}`, 20, startY + 30);

  const activity = ACTIVITIES[player.activity as keyof typeof ACTIVITIES];
  pdf.text(`Activity: ${activity?.emoji} ${activity?.label}`, 20, startY + 45);

