import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { generateReceipt } from "@/lib/pdf-generator";
import type { Player, Payment } from "@shared/schema";

interface ReceiptModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  player?: Player;
  payment?: Payment;
}

export default function ReceiptModal({ 
  open, 
  onOpenChange, 
  player, 
  payment 
}: ReceiptModalProps) {

  const handlePrint = () => {
    window.print();
  };

  const handleDownloadPDF = () => {
    if (player && payment) {
      const pdf = generateReceipt(player, payment);
      pdf.save(`receipt-${payment.receiptNumber}.pdf`);
    }
  };

  if (!player || !payment) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Payment Receipt</DialogTitle>
          <DialogDescription>
            Download or print payment receipt for {player.fullName}
          </DialogDescription>
        </DialogHeader>

        <div id="receipt-content" className="p-6">
          {/* Receipt Header */}
          <div className="text-center mb-6">
            <div className="flex items-center justify-center space-x-3 mb-2">
              <div className="w-12 h-12 bg-academy-blue rounded-full flex items-center justify-center">
                <span className="text-white font-bold text-lg">E1</span>
              </div>
              <div>
                <h2 className="text-xl font-bold text-gray-900">E1 Sport</h2>
                <p className="text-sm text-academy-red font-medium">Champions Academy</p>
              </div>
            </div>
            <p className="text-sm text-gray-600">Payment Receipt</p>
          </div>

          {/* Receipt Details */}
          <div className="space-y-3 mb-6">
            <div className="flex justify-between">
              <span className="text-sm text-gray-600">Receipt #:</span>
              <span className="text-sm font-medium">{payment.receiptNumber}</span>
