            <h3 className="text-lg font-medium text-gray-900 border-b pb-2 mb-3">Documents</h3>
            {playerData.documents && playerData.documents.length > 0 ? (
              <div className="space-y-2">
                {playerData.documents.map((doc: any) => (
                  <div key={doc.id} className="flex items-center justify-between p-2 bg-gray-50 rounded">
                    <span className="text-sm text-gray-700">{doc.documentType}</span>
                    <Button variant="link" size="sm">View</Button>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-sm text-gray-500">No documents uploaded</p>
            )}
          </div>

          {/* Payment Section with Current and History */}
          <PaymentSection playerId={playerId} />
        </div>

        {/* Special Notes */}
        {playerData.specialNotes && (
          <div className="mt-6">
            <h3 className="text-lg font-medium text-gray-900 border-b pb-2 mb-3">Special Notes</h3>
