import React, { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Receipt, Calendar, Filter } from "lucide-react";
import { PAYMENT_METHODS, PAYMENT_STATUS_COLORS } from "@/lib/constants";
import { format, startOfMonth, endOfMonth, parseISO } from "date-fns";
import ReceiptModal from "@/components/modals/receipt-modal";

export default function PaymentRecords() {
  const [selectedPlayer, setSelectedPlayer] = useState<string>("all");
  const [selectedMonth, setSelectedMonth] = useState<string>(format(new Date(), 'yyyy-MM'));
  const [receiptModalOpen, setReceiptModalOpen] = useState(false);
  const [selectedPayment, setSelectedPayment] = useState<any>(null);
  const [selectedPlayerData, setSelectedPlayerData] = useState<any>(null);

  const { data: payments, isLoading, refetch } = useQuery({
    queryKey: ["/api/payments", selectedPlayer, selectedMonth],
    queryFn: async () => {
      let url = `/api/payments?`;
      if (selectedPlayer !== "all") {
        url += `playerId=${selectedPlayer}&`;
      }
      if (selectedMonth) {
        const startDate = startOfMonth(parseISO(selectedMonth + '-01')).toISOString();
        const endDate = endOfMonth(parseISO(selectedMonth + '-01')).toISOString();
        url += `startDate=${startDate}&endDate=${endDate}`;
      }
      const response = await fetch(url);
      if (!response.ok) throw new Error('Failed to fetch payments');
      return response.json();
    },
    staleTime: 0,
    gcTime: 0,
  });

  const { data: players } = useQuery({
    queryKey: ["/api/players"],
  });

  const handleReceiptClick = async (payment: any) => {
    try {
      const response = await fetch(`/api/players/${payment.playerId}`);
      if (response.ok) {
        const playerData = await response.json();
        setSelectedPayment(payment);
        setSelectedPlayerData(playerData);
        setReceiptModalOpen(true);
      }
    } catch (error) {
      console.error('Failed to fetch player data:', error);
    }
  };



  // Force refetch when component mounts
  React.useEffect(() => {
    refetch();
  }, [refetch]);

  // Generate months for the last 12 months
  const getMonthOptions = () => {
    const months = [];
    for (let i = 0; i < 12; i++) {
      const date = new Date();
      date.setMonth(date.getMonth() - i);
      months.push({
        value: format(date, 'yyyy-MM'),
        label: format(date, 'MMMM yyyy')
      });
    }
    return months;
  };

  if (isLoading) {
    return (
      <div className="lg:col-span-2">
        <Card className="animate-pulse">
          <CardContent className="p-6">
            <div className="h-64 bg-gray-200 rounded"></div>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <>
      <div className="lg:col-span-2">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center justify-between">
              <span>Payment Records</span>
              <div className="flex items-center space-x-4">
                <div className="flex items-center space-x-2">
                  <Filter className="h-4 w-4 text-gray-500" />
                  <Select value={selectedPlayer} onValueChange={setSelectedPlayer}>
                    <SelectTrigger className="w-48">
                      <SelectValue placeholder="Filter by player" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">All Players</SelectItem>
                      {(players as any)?.map((player: any) => (
                        <SelectItem key={player.id} value={player.id}>
                          {player.fullName}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="flex items-center space-x-2">
                  <Calendar className="h-4 w-4 text-gray-500" />
                  <Select value={selectedMonth} onValueChange={setSelectedMonth}>
                    <SelectTrigger className="w-40">
                      <SelectValue placeholder="Select month" />
                    </SelectTrigger>
                    <SelectContent>
                      {getMonthOptions().map((month) => (
                        <SelectItem key={month.value} value={month.value}>
                          {month.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Player
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Amount
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Method
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Date
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Status
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {(payments as any)?.slice(0, 20).map((payment: any) => {
                    const method = PAYMENT_METHODS[payment.paymentMethod as keyof typeof PAYMENT_METHODS];
                    return (
                      <tr key={payment.id}>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="text-sm font-medium text-gray-900">{payment.playerName || payment.fullName || 'Unknown Player'}</div>
                          <div className="text-sm text-gray-500">{payment.description || 'Subscription payment'}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="text-sm text-gray-900">${payment.amountPaid}</div>
                          <div className="text-xs text-gray-500">
                            Balance: ${payment.remainingBalance}
                          </div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center space-x-2">
                            <span className="text-lg">{method?.icon}</span>
                            <span className="text-sm">{method?.label}</span>
                          </div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                          {format(new Date(payment.paymentDate), 'MMM dd, yyyy')}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${PAYMENT_STATUS_COLORS[payment.paymentStatus as keyof typeof PAYMENT_STATUS_COLORS]}`}>
                            {payment.paymentStatus.charAt(0).toUpperCase() + payment.paymentStatus.slice(1)}
                          </span>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                          <Button 
                            variant="link" 
                            className="text-academy-blue hover:text-academy-blue-light p-0"
