import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { User, Eye, Edit, Printer, Calendar } from "lucide-react";
import { Button } from "@/components/ui/button";
import { ACTIVITIES, SUBSCRIPTION_STATUS_COLORS } from "@/lib/constants";
import { format } from "date-fns";
import ViewPlayerModal from "@/components/modals/view-player-modal";
import EditPlayerModal from "@/components/modals/edit-player-modal";
import AddPaymentModal from "@/components/modals/add-payment-modal";
import AddAdditionalPaymentModal from "@/components/modals/add-additional-payment-modal";


interface PlayersTableProps {
  searchTerm: string;
  activityFilter: string;
}

export default function PlayersTable({ searchTerm, activityFilter }: PlayersTableProps) {
  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedPlayer, setSelectedPlayer] = useState<any>(null);
  const [showViewModal, setShowViewModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showAdditionalPaymentModal, setShowAdditionalPaymentModal] = useState(false);


  const { data: players, isLoading } = useQuery({
    queryKey: ["/api/players"],
  });

  const filteredPlayers = (players as any)?.filter((player: any) => {
    const matchesSearch = player.fullName.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesActivity = !activityFilter || activityFilter === "all" || player.activity === activityFilter;
    return matchesSearch && matchesActivity;
  }) || [];

  if (isLoading) {
    return (
      <div className="overflow-x-auto">
        <div className="min-w-full animate-pulse">
          {[...Array(5)].map((_, i) => (
            <div key={i} className="h-16 border-b border-gray-200 bg-gray-50"></div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
              Player
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
              Activity
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
              Subscription
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
              Payment Status
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
              Sessions
            </th>
            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
              Actions
            </th>
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-gray-200">
          {filteredPlayers.map((player: any) => {
            const activity = ACTIVITIES[player.activity as keyof typeof ACTIVITIES];
            const age = new Date().getFullYear() - new Date(player.dateOfBirth).getFullYear();

            return (
              <tr key={player.id}>
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center">
                    <div className="w-10 h-10 bg-gray-300 rounded-full flex items-center justify-center">
                      <User className="h-5 w-5 text-gray-600" />
                    </div>
                    <div className="ml-4">
                      <div className="text-sm font-medium text-gray-900">{player.fullName}</div>
                      <div className="text-sm text-gray-500">
                        ID: #{player.id.slice(0, 8)} • Age: {age}
                      </div>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                    {activity.emoji} {activity.label}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                  <div>
                    {format(new Date(player.subscriptionDate), 'MMM dd, yyyy')} - {format(new Date(player.subscriptionEndDate || player.renewalDate), 'MMM dd, yyyy')}
                  </div>
                  <div className="text-xs text-gray-500">
                    {(() => {
                      const startDate = new Date(player.subscriptionDate);
                      const endDate = new Date(player.subscriptionEndDate || player.renewalDate);
                      const diffTime = Math.abs(endDate.getTime() - startDate.getTime());
                      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

                      if (diffDays <= 7) return `${diffDays} Day${diffDays > 1 ? 's' : ''} Plan`;
                      if (diffDays <= 14) return `${Math.round(diffDays / 7)} Week${Math.round(diffDays / 7) > 1 ? 's' : ''} Plan`;
                      if (diffDays <= 45) return `${Math.round(diffDays / 30)} Month${Math.round(diffDays / 30) > 1 ? 's' : ''} Plan`;
                      return `${Math.round(diffDays / 30)} Month${Math.round(diffDays / 30) > 1 ? 's' : ''} Plan`;
                    })()}
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${SUBSCRIPTION_STATUS_COLORS[player.subscriptionStatus as keyof typeof SUBSCRIPTION_STATUS_COLORS]}`}>
                    {player.subscriptionStatus === 'active' ? 'Active' : 
                     player.subscriptionStatus === 'expired' ? 'Expired' :
                     player.subscriptionStatus === 'renewal_due' ? 'Renewal Due' : 'Cancelled'}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="text-sm text-gray-900">
                    {player.sessionsAttended}/{player.totalSessionsAllowed} attended
                  </div>
                  <div className="text-xs text-gray-500">
                    {Math.max(0, player.totalSessionsAllowed - player.sessionsAttended)} remaining
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium space-x-2">
                  <Button 
                    variant="link" 
                    className="text-academy-blue hover:text-academy-blue-light p-0"
                    onClick={() => {
                      setSelectedPlayerId(player.id);
                      setShowViewModal(true);
                    }}
                  >
                    <Eye className="h-4 w-4 mr-1" />
                    View
                  </Button>
                  <Button 
                    variant="link" 
                    className="text-blue-600 hover:text-blue-700 p-0"
                    onClick={() => {
                      setSelectedPlayer(player);
                      setShowEditModal(true);
                    }}
                  >
                    <Edit className="h-4 w-4 mr-1" />
                    Edit
                  </Button>
                  <Button 
                    variant="link" 
                    className="text-green-600 hover:text-green-700 p-0"
                    onClick={() => {
                      setSelectedPlayerId(player.id);
                      setSelectedPlayer(player);
                      setShowAdditionalPaymentModal(true);
                    }}
                  >
                    <Edit className="h-4 w-4 mr-1" />
                    Add Payment
                  </Button>

                  <Button 
                    variant="link" 
                    className="text-purple-600 hover:text-purple-700 p-0"
                    onClick={() => {
                      setSelectedPlayerId(player.id);
                      setShowViewModal(true);
                    }}
                  >
                    <Printer className="h-4 w-4 mr-1" />
                    Print
                  </Button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>

      {/* Modals */}
      <ViewPlayerModal
        open={showViewModal}
        onOpenChange={setShowViewModal}
        playerId={selectedPlayerId}
      />

      <AddPaymentModal
        open={showPaymentModal}
        onOpenChange={setShowPaymentModal}
        selectedPlayerId={selectedPlayerId || undefined}
      />



      <EditPlayerModal
        open={showEditModal}
        onOpenChange={setShowEditModal}
        player={selectedPlayer}
      />

      <AddAdditionalPaymentModal
        open={showAdditionalPaymentModal}
        onOpenChange={setShowAdditionalPaymentModal}
        playerId={selectedPlayerId || undefined}
        playerName={selectedPlayer?.fullName || undefined}
      />
    </div>
  );
}

