                    </Button>
                  </CardContent>
                </Card>
              );
            })}
          </div>

          {filteredPlayers.length === 0 && (
            <div className="text-center py-12">
              <Users className="h-12 w-12 text-gray-400 mx-auto mb-4" />
              <p className="text-gray-600">No players found matching your filters.</p>
            </div>
